import os
import uuid
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
from PIL import Image
import magic
from pathlib import Path

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif'}
MAX_FILE_SIZE = 5 * 1024 * 1024  # 5MB
MAX_IMAGE_DIMENSION = 2000  # pixels
UPLOAD_DIR = Path(UPLOAD_FOLDER)
UPLOAD_DIR.mkdir(exist_ok=True)

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def is_valid_image(file_path):
    try:
        with Image.open(file_path) as img:
            img.verify()
        return True
    except Exception:
        return False

def get_file_mime_type(file_path):
    mime = magic.Magic(mime=True)
    return mime.from_file(str(file_path))

def validate_and_process_image(file_path):
    # Check file size
    if os.path.getsize(file_path) > MAX_FILE_SIZE:
        raise ValueError("File too large")
    
    # Check MIME type
    mime_type = get_file_mime_type(file_path)
    if mime_type not in ['image/jpeg', 'image/png', 'image/gif']:
        raise ValueError("Invalid file type")
    
    # Validate image integrity
    if not is_valid_image(file_path):
        raise ValueError("Invalid image file")
    
    # Check dimensions
    with Image.open(file_path) as img:
        if img.width > MAX_IMAGE_DIMENSION or img.height > MAX_IMAGE_DIMENSION:
            raise ValueError("Image dimensions too large")

@app.route('/upload_profile_picture', methods=['POST'])
def upload_profile_picture():
    if 'profile_picture' not in request.files:
        return jsonify({"error": "No file part"}), 400
    
    file = request.files['profile_picture']
    
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400
    
    if not allowed_file(file.filename):
        return jsonify({"error": "Invalid file type"}), 400
    
    try:
        # Generate secure filename
        original_filename = secure_filename(file.filename)
        file_extension = original_filename.rsplit('.', 1)[1].lower()
        unique_filename = f"{uuid.uuid4().hex}.{file_extension}"
        
        # Save to secure location
        save_path = UPLOAD_DIR / unique_filename
        file.save(save_path)
        
        # Validate image
        validate_and_process_image(save_path)
        
        # Return success response
        return jsonify({
            "message": "Profile picture uploaded successfully",
            "filename": unique_filename
        }), 200
        
    except ValueError as e:
        # Remove file if validation fails
        if save_path.exists():
            save_path.unlink()
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        # Remove file if any other error occurs
        if save_path.exists():
            save_path.unlink()
        return jsonify({"error": "Internal server error"}), 500

if __name__ == '__main__':
    app.run(debug=False)